#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <chrono>

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = memcmp(ref_out, out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (ref_out[i] != out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

template<typename T, int N>
__global__ void scan_with_bank_conflicts(const T* in, T* out, int64_t num_blocks)
{
  __shared__ T temp[N];
  int bid = blockIdx.x;
  if (bid >= num_blocks) return;

  const T* t_in  = in + bid * N;
  T* t_out = out + bid * N;

  int thid = threadIdx.x;

  // Each thread loads two elements
  int idx0 = 2 * thid;
  int idx1 = idx0 + 1;

  if (idx1 < N) {
    temp[idx0] = t_in[idx0];
    temp[idx1] = t_in[idx1];
  }

  __syncthreads();

  int offset = 1;
  for (int d = N >> 1; d > 0; d >>= 1)
  {
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      temp[bi] += temp[ai];
    }
    offset *= 2;
    __syncthreads();
  }

  if (thid == 0) temp[N-1] = 0;
  for (int d = 1; d < N; d *= 2)
  {
    offset >>= 1;
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
    __syncthreads();
  }

  if (idx1 < N) {
    t_out[idx0] = temp[idx0];
    t_out[idx1] = temp[idx1];
  }
}

template<typename T, int N>
__global__ void scan_without_bank_conflicts(const T* in, T* out, int64_t num_blocks)
{
  extern __shared__ char shared_mem[];
  T* temp = (T*)shared_mem;

  int bid = blockIdx.x;
  if (bid >= num_blocks) return;

  const T* t_in  = in + bid * N;
  T* t_out = out + bid * N;

  int thid = threadIdx.x;

  int a = thid;
  int b = a + (N/2);
  int oa = OFFSET(a);
  int ob = OFFSET(b);

  temp[a + oa] = t_in[a];
  temp[b + ob] = t_in[b];

  __syncthreads();

  int offset = 1;
  for (int d = N >> 1; d > 0; d >>= 1)
  {
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      temp[bi] += temp[ai];
    }
    offset *= 2;
    __syncthreads();
  }

  if (thid == 0) temp[N-1+OFFSET(N-1)] = 0;
  for (int d = 1; d < N; d *= 2)
  {
    offset >>= 1;
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
    __syncthreads();
  }
  __syncthreads();

  t_out[a] = temp[a + oa];
  t_out[b] = temp[b + ob];
}

template<typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N;
  int64_t bytes = nelems * sizeof(T);

  T *in = (T*) malloc (bytes);
  T *out = (T*) malloc (bytes);
  T *ref_out = (T*) malloc (bytes);

  srand(123);
  for (int64_t i = 0; i < nelems; i++) in[i] = rand() % 5 + 1;

  T *t_in = in;
  T *t_out = ref_out;
  for (int64_t i = 0; i < num_blocks; i++) {
    t_out[0] = 0;
    for (int j = 1; j < N; j++)
      t_out[j] = t_out[j-1] + t_in[j-1];
    t_out += N;
    t_in += N;
  }

  T *d_in, *d_out;
  cudaMalloc(&d_in, bytes);
  cudaMalloc(&d_out, bytes);
  cudaMemcpy(d_in, in, bytes, cudaMemcpyHostToDevice);

  // Scan with bank conflicts
  auto start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scan_with_bank_conflicts<T,N><<<num_blocks, N/2>>>(d_in, d_out, num_blocks);
    cudaDeviceSynchronize();
  }
  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }

  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out, out, nelems);

  // Scan without bank conflicts
  start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    size_t shared_mem_size = (2*N + OFFSET(2*N-1)) * sizeof(T);
    scan_without_bank_conflicts<T,N><<<num_blocks, N/2, shared_mem_size>>>(d_in, d_out, num_blocks);
    cudaDeviceSynchronize();
  }
  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }

  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out, out, nelems);

  cudaFree(d_in);
  cudaFree(d_out);
  free(in);
  free(out);
  free(ref_out);
}

template<int N>
void run (const int n, const int repeat) {
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (argc != 3) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int n = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  run< 128>(n, repeat);
  run< 256>(n, repeat);
  run< 512>(n, repeat);
  run<1024>(n, repeat);
  run<2048>(n, repeat);

  return 0;
}
